mapper.select:
SELECT A.NLVL_MST_SEQ , A.NUN_ASSIGN_BLOCK_CNT , A.NRESERVE_ASSIGN_BLOCK_CNT , A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD , A.SSVC_OBJ_NM , A.RNUM FROM ( SELECT A.NLVL_MST_SEQ , A.NUN_ASSIGN_BLOCK_CNT , A.NRESERVE_ASSIGN_BLOCK_CNT , A.SSVC_LINE_TYPE_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD , A.SSVC_OBJ_NM , ROWNUM RNUM FROM ( SELECT A.NLVL_MST_SEQ ,A.SSVC_LINE_TYPE_CD AS SSVC_LINE_TYPE_CD , C.SSVC_LINE_TYPE_NM AS SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD AS SSVC_GROUP_CD , D.SLVL_NM AS SSVC_GROUP_NM , A.SSVC_OBJ_CD AS SSVC_OBJ_CD , E.SLVL_NM AS SSVC_OBJ_NM , NVL(ROUND(B.NU,0),0) AS NUN_ASSIGN_BLOCK_CNT , NVL(ROUND(B.US,0),0) AS NRESERVE_ASSIGN_BLOCK_CNT FROM MST.TB_LVL_MST A ,( SELECT MM.NLVL_MST_SEQ , SUM(DECODE(SASSIGN_LEVEL_CD,'IA0001', NCLASS_CNT,0)) AS NU , SUM(DECODE(SASSIGN_LEVEL_CD,'IA0002', NCLASS_CNT,0)) AS US , SUM(NCLASS_CNT) AS NCLASS_CNT FROM MST.TB_IP_ASSIGN_MST MM WHERE SIP_VERSION_TYPE_CD = 'CV0001' AND SASSIGN_LEVEL_CD IN ('IA0001','IA0002') AND SIP_CREATE_TYPE_CD != 'CT0005' -- 사설ip는 3계위까지 지정 후 생성되기때문에 제외함 GROUP BY MM.NLVL_MST_SEQ ) B , MST.TB_SVC_LINE_TYPE_CD C , MST.TB_LVL_CD D , MST.TB_LVL_CD E WHERE A.NLVL_MST_SEQ = B.NLVL_MST_SEQ(+) AND A.SSVC_LINE_TYPE_CD = C.SSVC_LINE_TYPE_CD(+) AND A.SSVC_GROUP_CD = D.SLVL_CD(+) AND A.SSVC_OBJ_CD = E.SLVL_CD(+)
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT COUNT(1) totalCount FROM MST.TB_LVL_MST A ,( SELECT MM.NLVL_MST_SEQ , SUM(DECODE(SASSIGN_LEVEL_CD,'IA0001', NCLASS_CNT,0)) AS NU , SUM(DECODE(SASSIGN_LEVEL_CD,'IA0002', NCLASS_CNT,0)) AS US , SUM(NCLASS_CNT) AS NCLASS_CNT FROM MST.TB_IP_ASSIGN_MST MM WHERE SIP_VERSION_TYPE_CD = 'CV0001' AND SASSIGN_LEVEL_CD IN ('IA0001','IA0002') AND SIP_CREATE_TYPE_CD != 'CT0005' -- 사설ip는 3계위까지 지정 후 생성되기때문에 제외함 GROUP BY MM.NLVL_MST_SEQ ) B , MST.TB_SVC_LINE_TYPE_CD C , MST.TB_LVL_CD D , MST.TB_LVL_CD E WHERE A.NLVL_MST_SEQ = B.NLVL_MST_SEQ(+) AND A.SSVC_LINE_TYPE_CD = C.SSVC_LINE_TYPE_CD(+) AND A.SSVC_GROUP_CD = D.SLVL_CD(+) AND A.SSVC_OBJ_CD = E.SLVL_CD(+)
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}

SELECT A.SSVC_LINE_TYPE_CD, A.SSVC_LINE_TYPE_NM, A.SSVC_GROUP_CD, A.SSVC_GROUP_NM, A.SSVC_OBJ_CD, A.SSVC_OBJ_NM, A.PIP_PREFIX, A.NCNT , A.RNUM FROM ( SELECT A.SSVC_LINE_TYPE_CD, A.SSVC_LINE_TYPE_NM, A.SSVC_GROUP_CD, A.SSVC_GROUP_NM, A.SSVC_OBJ_CD, A.SSVC_OBJ_NM, A.PIP_PREFIX, A.NCNT , ROWNUM RNUM FROM ( SELECT A.SSVC_LINE_TYPE_CD, A.SSVC_LINE_TYPE_NM, A.SSVC_GROUP_CD, A.SSVC_GROUP_NM, A.SSVC_OBJ_CD, A.SSVC_OBJ_NM, A.PIP_PREFIX, A.NCNT FROM ( SELECT B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD, C.SSVC_LINE_TYPE_NM, D.SLVL_NM SSVC_GROUP_NM, E.SLVL_NM SSVC_OBJ_NM , NETWORK(INET(SIP_BLOCK || '/24')) PIP_PREFIX, SUM(A.NCNT) NCNT FROM MST.TB_IP_ASSIGN_MST A , MST.TB_LVL_MST B , MST.TB_SVC_LINE_TYPE_CD C , MST.TB_LVL_CD D , MST.TB_LVL_CD E WHERE A.SIP_VERSION_TYPE_CD = 'CV0001' AND A.NBITMASK > 24 AND A.SASSIGN_LEVEL_CD NOT IN ('IA0005', 'IA0006') AND A.NLVL_MST_SEQ = B.NLVL_MST_SEQ AND B.SSVC_LINE_TYPE_CD = C.SSVC_LINE_TYPE_CD(+) AND B.SSVC_GROUP_CD = D.SLVL_CD(+) AND B.SSVC_OBJ_CD = E.SLVL_CD(+)
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
AND A.SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}
GROUP BY B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD, C.SSVC_LINE_TYPE_NM, D.SLVL_NM, E.SLVL_NM, NETWORK(INET(SIP_BLOCK || '/24')) ORDER BY NCNT ASC ) A
1 = 1
AND A.NCNT BETWEEN
65 AND 128 33 AND 64 17 AND 32 9 AND 16 5 AND 8 3 AND 4 2 AND 2 1 AND 1 1 AND 256
AND TEXT(A.PIP_PREFIX) LIKE #{searchWrd} || '%'
) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT COUNT(1) totalCount FROM ( SELECT A.SSVC_LINE_TYPE_CD, A.SSVC_LINE_TYPE_NM, A.SSVC_GROUP_CD, A.SSVC_GROUP_NM, A.SSVC_OBJ_CD, A.SSVC_OBJ_NM, A.PIP_PREFIX, A.NCNT FROM ( SELECT B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD, C.SSVC_LINE_TYPE_NM, D.SLVL_NM SSVC_GROUP_NM, E.SLVL_NM SSVC_OBJ_NM , NETWORK(INET(SIP_BLOCK || '/24')) PIP_PREFIX, SUM(A.NCNT) NCNT FROM MST.TB_IP_ASSIGN_MST A , MST.TB_LVL_MST B , MST.TB_SVC_LINE_TYPE_CD C , MST.TB_LVL_CD D , MST.TB_LVL_CD E WHERE A.SIP_VERSION_TYPE_CD = 'CV0001' AND A.NBITMASK > 24 AND A.SASSIGN_LEVEL_CD NOT IN ('IA0005', 'IA0006') AND A.NLVL_MST_SEQ = B.NLVL_MST_SEQ AND B.SSVC_LINE_TYPE_CD = C.SSVC_LINE_TYPE_CD(+) AND B.SSVC_GROUP_CD = D.SLVL_CD(+) AND B.SSVC_OBJ_CD = E.SLVL_CD(+)
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
AND A.SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}
GROUP BY B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD, C.SSVC_LINE_TYPE_NM, D.SLVL_NM, E.SLVL_NM, NETWORK(INET(SIP_BLOCK || '/24')) ) A
1 = 1
AND A.NCNT BETWEEN
65 AND 128 33 AND 64 17 AND 32 9 AND 16 5 AND 8 3 AND 4 2 AND 2 1 AND 1 1 AND 256
AND TEXT(A.PIP_PREFIX) LIKE #{searchWrd} || '%'
)

