	)

SELECT count(1) totalCount FROM (
SELECT A.SSVC_LINE_TYPE_NM, A.SSVC_GROUP_NM, A.SSVC_HIGH_NM, NVL(A.SSVC_HIGH_NM,NVL(MAX(A.SSVC_OBJ_NM),'-')) AS SSVC_OBJ_NM, A.PIP_PREFIX, A.SAS_PATH, A.SCOMMUNITY FROM ( SELECT CASE WHEN A.SSVC_LINE_TYPE_NM IS NOT NULL THEN A.SSVC_LINE_TYPE_NM WHEN A.COM_SSVC_LINE_TYPE_NM IS NOT NULL THEN COM_SSVC_LINE_TYPE_NM ELSE '-' END SSVC_LINE_TYPE_NM, CASE WHEN A.SSVC_GROUP_NM IS NOT NULL THEN A.SSVC_GROUP_NM WHEN A.COM_SSVC_GROUP_NM IS NOT NULL THEN A.COM_SSVC_GROUP_NM ELSE '-' END SSVC_GROUP_NM, CASE WHEN A.SSVC_HIGH_NM IS NOT NULL THEN A.SSVC_HIGH_NM WHEN A.COM_SSVC_HIGH_NM IS NOT NULL THEN A.COM_SSVC_HIGH_NM ELSE '-' END SSVC_HIGH_NM, CASE WHEN A.SSVC_OBJ_NM IS NOT NULL THEN A.SSVC_OBJ_NM WHEN A.COM_SSVC_OBJ_NM IS NOT NULL THEN A.COM_SSVC_OBJ_NM ELSE '-' END SSVC_OBJ_NM, NVL(CAST(A.PROUTING_IP_PREFIX AS TEXT), '-') AS PIP_PREFIX, NVL(A.SAS_PATH, '-') AS SAS_PATH, NVL(A.SCOMMUNITY, '-') AS SCOMMUNITY, A.NLVL_MST_SEQ , A.NLVL_BAS_SEQ FROM ( SELECT A.SCOLLECT_TYPE, A.PROUTING_IP_PREFIX, A.SAS_PATH , A.SCOMMUNITY , A.NLVL_MST_SEQ, A.SSVC_LINE_TYPE_CD , B.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , C.SLVL_NM AS SSVC_GROUP_NM, A.SSVC_OBJ_CD , D.SLVL_NM AS SSVC_OBJ_NM, A.SSVC_HIGH_CD, E.SLVL_NM AS SSVC_HIGH_NM, F.NLVL_BAS_SEQ, H.SSVC_LINE_TYPE_CD AS COM_SSVC_LINE_TYPE_CD, I.SSVC_LINE_TYPE_NM AS COM_SSVC_LINE_TYPE_NM , H.SSVC_GROUP_CD AS COM_SSVC_GROUP_CD, J.SLVL_NM AS COM_SSVC_GROUP_NM, H.SSVC_OBJ_CD AS COM_SSVC_OBJ_CD, K.SLVL_NM AS COM_SSVC_OBJ_NM, H.SSVC_HIGH_CD AS COM_SSVC_HIGH_CD, L.SLVL_NM AS COM_SSVC_HIGH_NM FROM ( SELECT A.SCOLLECT_TYPE, A.PROUTING_IP_PREFIX, A.SAS_PATH , A.SCOMMUNITY , B.NLVL_MST_SEQ, C.SSVC_LINE_TYPE_CD , C.SSVC_GROUP_CD , C.SSVC_OBJ_CD , D.SSVC_HIGH_CD FROM MST.TB_INTGRM_SUMMARY_BAS_MST A, ( SELECT T.SCOLLECT_TYPE, T.NLVL_MST_SEQ, T.PROUTING_IP_PREFIX FROM MST.TB_INTGRM_SUMMARY_BAS_MST T WHERE T.SCOLLECT_TYPE IS NULL AND ( ( (T.NROUTING_FIRST_ADDR <= (SELECT NFIRST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) AND (T.NROUTING_LAST_ADDR >= (SELECT NLAST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) ) OR ( (T.NROUTING_FIRST_ADDR >= (SELECT NFIRST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) AND (T.NROUTING_LAST_ADDR <= (SELECT NLAST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) ) ) ) B , MST.TB_LVL_MST C, MST.TB_LVL_ROLE_MST D WHERE (A.SCOMMUNITY !~ '((4766:2)[0|1|2|3|4|6|8|9]{2})' AND A.SCOLLECT_TYPE = 'ALL_KORNET') AND ( ( (A.NROUTING_FIRST_ADDR <= (SELECT NFIRST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) AND (A.NROUTING_LAST_ADDR >= (SELECT NLAST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) ) OR ( (A.NROUTING_FIRST_ADDR >= (SELECT NFIRST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) AND (A.NROUTING_LAST_ADDR <= (SELECT NLAST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) ) ) AND A.PROUTING_IP_PREFIX = B.PROUTING_IP_PREFIX (+) AND B.NLVL_MST_SEQ = C.NLVL_MST_SEQ(+) AND C.SSVC_LINE_TYPE_CD = D.SSVC_LINE_TYPE_CD (+) AND C.SSVC_GROUP_CD = D.SSVC_GROUP_CD (+) AND C.SSVC_OBJ_CD = D.SSVC_OBJ_CD (+) ) A , MST.TB_SVC_LINE_TYPE_CD B, MST.TB_LVL_CD C, MST.TB_LVL_CD D, MST.TB_LVL_CD E, MST.TB_WIRE_IP_COMMU_MST F, MST.TB_LVL_BAS G, MST.TB_LVL_ROLE_MST H, MST.TB_SVC_LINE_TYPE_CD I, MST.TB_LVL_CD J, MST.TB_LVL_CD K, MST.TB_LVL_CD L WHERE A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD (+) AND A.SSVC_GROUP_CD = C.SLVL_CD (+) AND A.SSVC_OBJ_CD = D.SLVL_CD (+) AND A.SSVC_HIGH_CD = E.SLVL_CD (+) AND F.SCOMMUNITY(+) LIKE '%'|| (CASE WHEN A.SCOMMUNITY = '' OR A.SCOMMUNITY IS NULL THEN 'XXXXXXXXXXXXX' ELSE A.SCOMMUNITY END) ||'%' AND F.NLVL_BAS_SEQ = G.NLVL_BAS_SEQ (+) AND G.SSVC_LINE_TYPE_CD = H.SSVC_LINE_TYPE_CD (+) AND G.SSVC_GROUP_CD = H.SSVC_GROUP_CD (+) AND G.SSVC_OBJ_CD = H.SSVC_OBJ_CD (+) AND H.SSVC_LINE_TYPE_CD = I.SSVC_LINE_TYPE_CD (+) AND H.SSVC_GROUP_CD = J.SLVL_CD (+) AND H.SSVC_OBJ_CD = K.SLVL_CD (+) AND H.SSVC_HIGH_CD = L.SLVL_CD (+) ) A ) A GROUP BY A.SSVC_LINE_TYPE_NM, A.SSVC_GROUP_NM, A.SSVC_HIGH_NM, A.PIP_PREFIX, A.SAS_PATH, A.SCOMMUNITY ORDER BY PIP_PREFIX
)

SELECT count(1) totalCount FROM (
SELECT A.SSVC_LINE_TYPE_NM, A.SSVC_GROUP_NM, A.SSVC_HIGH_NM, A.SSVC_OBJ_NM, A.PIP_PREFIX, A.SAS_PATH, A.SCOMMUNITY FROM ( SELECT CASE WHEN A.SSVC_LINE_TYPE_NM IS NOT NULL THEN A.SSVC_LINE_TYPE_NM WHEN A.COM_SSVC_LINE_TYPE_NM IS NOT NULL THEN COM_SSVC_LINE_TYPE_NM ELSE '-' END SSVC_LINE_TYPE_NM, CASE WHEN A.SSVC_GROUP_NM IS NOT NULL THEN A.SSVC_GROUP_NM WHEN A.COM_SSVC_GROUP_NM IS NOT NULL THEN A.COM_SSVC_GROUP_NM ELSE '-' END SSVC_GROUP_NM, CASE WHEN A.SSVC_HIGH_NM IS NOT NULL THEN A.SSVC_HIGH_NM WHEN A.COM_SSVC_HIGH_NM IS NOT NULL THEN A.COM_SSVC_HIGH_NM ELSE '-' END SSVC_HIGH_NM, CASE WHEN A.SSVC_OBJ_NM IS NOT NULL THEN A.SSVC_OBJ_NM WHEN A.COM_SSVC_OBJ_NM IS NOT NULL THEN A.COM_SSVC_OBJ_NM ELSE '-' END SSVC_OBJ_NM, NVL(CAST(A.PROUTING_IP_PREFIX AS TEXT), '-') AS PIP_PREFIX, NVL(A.SAS_PATH, '-') AS SAS_PATH, NVL(A.SCOMMUNITY, '-') AS SCOMMUNITY, A.NLVL_MST_SEQ , A.NLVL_BAS_SEQ FROM ( SELECT A.SCOLLECT_TYPE, A.PROUTING_IP_PREFIX, A.SAS_PATH , A.SCOMMUNITY , A.NLVL_MST_SEQ, A.SSVC_LINE_TYPE_CD , B.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , C.SLVL_NM AS SSVC_GROUP_NM, A.SSVC_OBJ_CD , D.SLVL_NM AS SSVC_OBJ_NM, A.SSVC_HIGH_CD, E.SLVL_NM AS SSVC_HIGH_NM, F.NLVL_BAS_SEQ, H.SSVC_LINE_TYPE_CD AS COM_SSVC_LINE_TYPE_CD, I.SSVC_LINE_TYPE_NM AS COM_SSVC_LINE_TYPE_NM , H.SSVC_GROUP_CD AS COM_SSVC_GROUP_CD, J.SLVL_NM AS COM_SSVC_GROUP_NM, H.SSVC_OBJ_CD AS COM_SSVC_OBJ_CD, K.SLVL_NM AS COM_SSVC_OBJ_NM, H.SSVC_HIGH_CD AS COM_SSVC_HIGH_CD, L.SLVL_NM AS COM_SSVC_HIGH_NM FROM ( SELECT A.SCOLLECT_TYPE, A.PROUTING_IP_PREFIX, A.SAS_PATH , A.SCOMMUNITY , B.NLVL_MST_SEQ, CASE WHEN B.SIP_NEXTHOP IS NULL OR B.SIP_NEXTHOP ='' THEN A.SIP_NEXTHOP ELSE B.SIP_NEXTHOP END AS SIP_NEXTHOP , C.SSVC_LINE_TYPE_CD , C.SSVC_GROUP_CD , C.SSVC_OBJ_CD , D.SSVC_HIGH_CD FROM MST.TB_INTGRM_SUMMARY_BAS_MST A, ( SELECT T.SCOLLECT_TYPE, T.NLVL_MST_SEQ, T.PROUTING_IP_PREFIX, T.SIP_NEXTHOP FROM MST.TB_INTGRM_SUMMARY_BAS_MST T WHERE T.SCOLLECT_TYPE IS NULL AND ( ( (T.NROUTING_FIRST_ADDR <= (SELECT NFIRST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) AND (T.NROUTING_LAST_ADDR >= (SELECT NLAST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) ) OR ( (T.NROUTING_FIRST_ADDR >= (SELECT NFIRST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) AND (T.NROUTING_LAST_ADDR <= (SELECT NLAST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) ) ) ) B , MST.TB_LVL_MST C, MST.TB_LVL_ROLE_MST D WHERE (A.SCOMMUNITY !~ '((4766:2)[0-9]{2})' AND A.SCOLLECT_TYPE = 'ALL_PREMIUM') AND( ( (A.NROUTING_FIRST_ADDR <= (SELECT NFIRST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) AND (A.NROUTING_LAST_ADDR >= (SELECT NLAST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) ) OR ( (A.NROUTING_FIRST_ADDR >= (SELECT NFIRST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) AND (A.NROUTING_LAST_ADDR <= (SELECT NLAST_ADDR FROM MST.TB_IP_ASSIGN_MST TIAM WHERE NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT})) ) ) AND A.PROUTING_IP_PREFIX = B.PROUTING_IP_PREFIX (+) AND B.NLVL_MST_SEQ = C.NLVL_MST_SEQ(+) AND C.SSVC_LINE_TYPE_CD = D.SSVC_LINE_TYPE_CD (+) AND C.SSVC_GROUP_CD = D.SSVC_GROUP_CD (+) AND C.SSVC_OBJ_CD = D.SSVC_OBJ_CD (+) ) A, MST.TB_SVC_LINE_TYPE_CD B, MST.TB_LVL_CD C, MST.TB_LVL_CD D, MST.TB_LVL_CD E, MST.TB_WIRE_IP_COMMU_MST F, MST.TB_LVL_MST G, MST.TB_LVL_ROLE_MST H, MST.TB_SVC_LINE_TYPE_CD I, MST.TB_LVL_CD J, MST.TB_LVL_CD K, MST.TB_LVL_CD L WHERE A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD (+) AND A.SSVC_GROUP_CD = C.SLVL_CD (+) AND A.SSVC_OBJ_CD = D.SLVL_CD (+) AND A.SSVC_HIGH_CD = E.SLVL_CD (+) AND A.SIP_NEXTHOP = F.SNEXTHOP(+) AND F.NLVL_BAS_SEQ = G.NLVL_MST_SEQ (+) AND G.SSVC_LINE_TYPE_CD = H.SSVC_LINE_TYPE_CD (+) AND G.SSVC_GROUP_CD = H.SSVC_GROUP_CD (+) AND G.SSVC_OBJ_CD = H.SSVC_OBJ_CD (+) AND H.SSVC_LINE_TYPE_CD = I.SSVC_LINE_TYPE_CD (+) AND H.SSVC_GROUP_CD = J.SLVL_CD (+) AND H.SSVC_OBJ_CD = K.SLVL_CD (+) AND H.SSVC_HIGH_CD = L.SLVL_CD (+) ) A ) A GROUP BY A.SSVC_LINE_TYPE_NM, A.SSVC_GROUP_NM, A.SSVC_HIGH_NM, A.SSVC_OBJ_NM, A.PIP_PREFIX, A.SAS_PATH, A.SCOMMUNITY ORDER BY PIP_PREFIX
)
